mapper.update:
UPDATE cf_account
SET user_id = #{userId}, account_book_id = #{accountBookId}, asset_account_id = #{assetAccountId}, category_id = #{categoryId}, type = #{type}, amount = #{amount}, remark = #{remark}, image_url = #{imageUrl}, location = #{location}, happened_at = #{happenedAt}, tags = #{tags}, is_reimbursed = #{isReimbursed}, updated_at = #{updatedAt}
WHERE id = #{id}

mapper.select:
SELECT COALESCE(SUM(amount), 0)
FROM cf_account
WHERE user_id = #{userId}
  AND type = #{type}
  AND happened_at >= #{startDate}
  AND happened_at <= #{endDate}

SELECT COUNT(*)
FROM cf_account
WHERE user_id = #{userId}
  AND happened_at >= #{startDate}
  AND happened_at <= #{endDate}

SELECT c.name AS category_name,
       SUM(a.amount) AS total_amount,
       COUNT(*) AS count
FROM cf_account a
LEFT JOIN cf_account_category c ON a.category_id = c.id
WHERE a.user_id = #{userId}
  AND a.type = #{type}
  AND a.happened_at >= #{startDate}
  AND a.happened_at <= #{endDate}
GROUP BY c.id, c.name
ORDER BY total_amount DESC

SELECT * FROM cf_account
WHERE user_id = #{userId}
ORDER BY happened_at DESC
LIMIT #{limit}

SELECT a.*
FROM cf_account a
WHERE a.user_id = #{userId}

    AND a.happened_at >= #{startDate}


    AND a.happened_at <= #{endDate}

ORDER BY a.happened_at DESC

SELECT tag_name AS tag, SUM(tag_amount) AS total_amount, COUNT(*) AS count FROM ( SELECT TRIM(SUBSTRING_INDEX(SUBSTRING_INDEX(a.tags, ',', n.n), ',', -1)) AS tag_name, a.amount AS tag_amount FROM cf_account a JOIN ( SELECT 1 AS n UNION ALL SELECT 2 UNION ALL SELECT 3 UNION ALL SELECT 4 UNION ALL SELECT 5 UNION ALL SELECT 6 UNION ALL SELECT 7 UNION ALL SELECT 8 UNION ALL SELECT 9 UNION ALL SELECT 10 ) n ON CHAR_LENGTH(a.tags) - CHAR_LENGTH(REPLACE(a.tags, ',', '')) >= n.n - 1 WHERE a.user_id = #{userId} AND a.tags IS NOT NULL AND a.tags != ''
AND a.happened_at >= #{startDate}
AND a.happened_at <= #{endDate}
) AS tag_data GROUP BY tag_name ORDER BY total_amount DESC

